package com.google.android.exoplayer.util.extensions;

import com.google.android.exoplayer.MediaFormat;
import java.nio.ByteBuffer;

/**
 * Input buffer to be used with extension renderers.
 */
public class InputBuffer extends Buffer {

  /**
   * Buffer which holds the data.
   */
  public ByteBuffer data;

  /**
   * The format of the media.
   */
  public MediaFormat format;

  /**
   * The presentation timestamp of the buffer in microseconds.
   */
  public long presentationTimeUs;

  /**
   * The index of the sample within the source.
   */
  public int sampleIndex;

  /**
   * Clears the buffer.
   */
  @Override
  public void clear() {
    super.clear();
    data = null;
    format = null;
    presentationTimeUs = 0;
    sampleIndex = 0;
  }

}
