```javascript
 class ListeningToQuery extends React.Component {
    constructor(props) {
        super(props);
        this.state = {
            dataSource: [],
            total: 0,
            loading: true,
            modalVisible: false,
            selectedRecord: {}
        };
    }
    componentDidMount() {
        this.fetchData();
    }
    fetchData = (params = {}) => {
        let self = this;
        self.setState({
            loading: true
        });
        http.post('/config/query/list', params).then(function (data) {
            if (data.success) {
                let dataSoureTmp = data.data;
                if(dataSoureTmp && dataSoureTmp.length > 0) {
                    dataSoureTmp.map((item,index) => {
                        item.key = index;
                        return item;
                    })
                }
                self.setState({
                    dataSource: dataSoureTmp || [],
                    total: dataSoureTmp.length || 0
                });
            }
        }).finally(function () {
            self.setState({
                loading: false
            });
        });
    }
    handleDelete = (record) => {
        let self = this;
        confirm({
            title: 'Are you sure delete this record?',
            onOk() {
                http.post('/config/query/delete', {
                    id: record.id
                }).then(function (data) {
                    if (data.success) {
                        message.success('Delete success!');
                        self.fetchData();
                    } else {
                        message.error(data.msg);
                    }
                });
            },
            onCancel() {
            },
        });
    }
    handleEdit = (record) => {
        this.setState({
            modalVisible: true,
            selectedRecord: record
        })
    }
    handleCancel = () => {
        this.setState({
            modalVisible: false,
            selectedRecord: {}
        })
    }
    handleOk = () => {
        this.fetchData();
        this.setState({
            modalVisible: false,
            selectedRecord: {}
        })
    }
    render() {
        const columns = [{
            title: 'ID',
            dataIndex: 'id',
            key: 'id',
        }, {
            title: 'Query Name',
            dataIndex: 'name',
            key: 'name',
        }, {
            title: 'Query',
            dataIndex: 'query',
            key: 'query',
        }, {
            title: 'Create Time',
            dataIndex: 'createTime',
            key: 'createTime',
        }, {
            title: 'Update Time',
            dataIndex: 'updateTime',
            key: 'updateTime',
        }, {
            title: 'Operation',
            key: 'operation',
            render: (text, record) => (
                <span>
                    <a onClick={() => this.handleEdit(record)}>Edit</a>
                    <Divider type="vertical" />
                    <a onClick={() => this.handleDelete(record)}>Delete</a>
                </span>
            ),
        }];
        return (
            <div>
                <Button type="primary" style={{ marginBottom: '20px' }} onClick={() => this.handleEdit({})}>
                    Add Query
                </Button>
                <Table columns={columns} dataSource={this.state.dataSource} loading={this.state.loading}  pagination={{
                    total:this.state.total,
                    showTotal: (total) => `Total ${total} items`
                }}/>
                <ListeningToQueryModal
                    visible={this.state.modalVisible}
                    handleCancel={this.handleCancel}
                    handleOk={this.handleOk}
                    selectedRecord={this.state.selectedRecord}
                />
            </div>
        );
    }
}
```

