  private int getPort() {
    int port = uri.getPort();
    if (port == -1) {
      String scheme = uri.getScheme();
      if (scheme.equals("wss")) {
        return WebSocket.DEFAULT_WSS_PORT;
      } else {
        if (scheme.equals("ws")) {
          return WebSocket.DEFAULT_PORT;
