import java.util.List;
import java.util.Map;

import javax.servlet.http.HttpServletRequest;

import org.junit.Before;
import org.junit.Test;
import org.mockito.ArgumentCaptor;
import org.mockito.Mock;
import org.mockito.MockitoAnnotations;

import org.springframework.cloud.netflix.zuul.filters.Route;
import org.springframework.cloud.netflix.zuul.filters.RouteLocator;
import org.springframework.mock.web.MockHttpServletRequest;
import org.springframework.mock.web.MockServletContext;
import org.springframework.web.servlet.HandlerExecutionChain;
import org.springframework.web.servlet.HandlerInterceptor;
import org.springframework.web.servlet.handler.AbstractHandlerMapping;
import org.springframework.web.util.UrlPathHelper;

import static org.assertj.core.api.Assertions.assertThat;
import static org.mockito.Matchers.any;
import static org.mockito.Mockito.when;

/**
 * @author Dave Syer
 */
public class ZuulHandlerMappingTests {

	@Mock
	private RouteLocator routeLocator;

	private ZuulHandlerMapping mapping;

	@Before
	public void init() {
		MockitoAnnotations.initMocks(this);
		this.mapping = new ZuulHandlerMapping(this.routeLocator);
		this.mapping.setServletContext(new MockServletContext());
	}

	@Test
	public void simplePath() throws Exception {
		when(this.routeLocator.getMatchingRoute("/foo")).thenReturn(new Route("foo",
				"/foo", "foo", "/foo", null, null, null));
		HandlerExecutionChain chain = this.mapping
				.getHandler(new MockHttpServletRequest("GET", "/foo"));
		assertThat(chain).isNotNull();
		assertThat(chain.getHandler()).isInstanceOf(ZuulController.class);
	}

	@Test
	public void pathWithWildcard() throws Exception {
		when(this.routeLocator.getMatchingRoute("/foo/bar")).thenReturn(new Route("foo",
				"/foo/**", "foo", "/foo/bar", null, null, null));
		HandlerExecutionChain chain = this.mapping
				.getHandler(new MockHttpServletRequest("GET", "/foo/bar"));
		assertThat(chain).isNotNull();
		assertThat(chain.getHandler()).isInstanceOf(ZuulController.class);
	}

	@Test
	public void pathWithMultiWildcard() throws Exception {
		when(this.routeLocator.getMatchingRoute("/foo/bar/baz"))
				.thenReturn(new Route("foo", "/foo/**", "foo", "/foo/bar/baz", null, null, null));
		HandlerExecutionChain chain = this.mapping
				.getHandler(new MockHttpServletRequest("GET", "/foo/bar/baz"));
		assertThat(chain).isNotNull();
		assertThat(chain.getHandler()).isInstanceOf(ZuulController.class);
	}

	@Test
	public void pathWithPathVariable() throws Exception {
		when(this.routeLocator.getMatchingRoute("/foo/1")).thenReturn(new Route("foo",
				"/foo/{id}", "foo", "/foo/1", null, null, null));
		HandlerExecutionChain chain = this.mapping
				.getHandler(new MockHttpServletRequest("GET", "/foo/1"));
		assertThat(chain).isNotNull();
		assertThat(chain.getHandler()).isInstanceOf(ZuulController.class);
	}

	@Test
	public void pathWithRegex() throws Exception {
		when(this.routeLocator.getMatchingRoute("/foo/123"))
				.thenReturn(new Route("foo", "/foo/(?<id>\\d+)", "foo", "/foo/123", null, null, null));
		HandlerExecutionChain chain = this.mapping
				.getHandler(new MockHttpServletRequest("GET", "/foo/123"));
		assertThat(chain).isNotNull();
		assertThat(chain.getHandler()).isInstanceOf(ZuulController.class);
	}

	@Test
	public void noMatch() throws Exception {
		when(this.routeLocator.getMatchingRoute("/foo")).thenReturn(null);
		HandlerExecutionChain chain = this.mapping
				.getHandler(new MockHttpServletRequest("GET", "/foo"));
		assertThat(chain).isNull();
	}

	@Test
	public void defaultInterceptors() throws Exception {
		when(this.routeLocator.getMatchingRoute("/foo")).thenReturn(new Route("foo",
				"/foo", "foo", "/foo", null, null, null));
		HandlerExecutionChain chain = this.mapping
				.getHandler(new MockHttpServletRequest("GET", "/foo"));
		assertThat(chain.getInterceptors()).hasSize(1);
		assertThat(chain.getInterceptors()[0]).isInstanceOf(ZuulHandlerInterceptor.class);
	}

	@Test
	public void customInterceptors() throws Exception {
		when(this.routeLocator.getMatchingRoute("/foo")).thenReturn(new Route("foo",
				"/foo", "foo", "/foo", null, null, null));
		List<HandlerInterceptor> interceptors = new ArrayList<>();
		interceptors.add(new TestHandlerInterceptor());
		this.mapping.setInterceptors(interceptors);
		HandlerExecutionChain chain = this.mapping
				.getHandler(new MockHttpServletRequest("GET", "/foo"));
		assertThat(chain.getInterceptors()).hasSize(2);
		assertThat(chain.getInterceptors()[0]).isInstanceOf(TestHandlerInterceptor.class);
		assertThat(chain.getInterceptors()[1]).isInstanceOf(ZuulHandlerInterceptor.class);
	}

	@Test
	public void pathHelper() throws Exception {
		UrlPathHelper pathHelper = new UrlPathHelper();
		pathHelper.setUrlDecode(false);
		this.mapping.setUrlPathHelper(pathHelper);
		when(this.routeLocator.getMatchingRoute("/foo/bar%2Fbaz"))
				.thenReturn(new Route("foo", "/foo/**", "foo", "/foo/bar%2Fbaz", null, null, null));
		HandlerExecutionChain chain = this.mapping
				.getHandler(new MockHttpServletRequest("GET", "/foo/bar%2Fbaz"));
		assertThat(chain).isNotNull();
		assertThat(chain.getHandler()).isInstanceOf(ZuulController.class);
	}

	@Test
	public void handlerNotModified() throws Exception {
		when(this.routeLocator.getMatchingRoute("/foo")).thenReturn(new Route("foo",
				"/foo", "foo", "/foo", null, null, null));
		MockHttpServletRequest request = new MockHttpServletRequest("GET", "/foo");
		this.mapping.getHandler(request);
		Object attribute = request.getAttribute(AbstractHandlerMapping.class.getName() + ".handler");
		assertThat(attribute).isNull();
	}

	private static class TestHandlerInterceptor implements HandlerInterceptor {
	}

}
```

